+fn decode_json_response<T: serde::de::DeserializeOwned>(
+    response: GoogleExecuteResponse,
+) -> GmailResult<T> {
+    match response.body {
+        GoogleResponseBody::Json(value) => serde_json::from_value(value).map_err(GmailError::Json),
